function Players() {
  return (
    <section className="page-card">
      <p className="eyebrow">Players</p>
      <h1>Legends and rising stars</h1>
      <div className="info-grid">
        {players.map((player) => (
          <article className="mini-card" key={player.name}>
            <img src={player.image} alt={`${player.name} cricket player`} />
            <h2>{player.name}</h2>
            <p className="tag">{player.role}</p>
            <p>{player.fact}</p>
          </article>
        ))}
      </div>
    </section>
  );
}

export default Players;
